import{_ as i,C as o,o as t,c as d,a2 as a,E as l}from"./chunks/framework.DnrXFDHb.js";const B=JSON.parse('{"title":"配置与发现笔记：把基础设施做成可替换入口","description":"","frontmatter":{},"headers":[],"relativePath":"agent/config-discovery-notes.md","filePath":"agent/config-discovery-notes.md","lastUpdated":1782239373000}'),E={name:"agent/config-discovery-notes.md"};function n(p,e,A,s,c,v){const r=o("Mermaid");return t(),d("div",null,[e[0]||(e[0]=a('<h1 id="配置与发现笔记-把基础设施做成可替换入口" tabindex="-1">配置与发现笔记：把基础设施做成可替换入口 <a class="header-anchor" href="#配置与发现笔记-把基础设施做成可替换入口" aria-label="Permalink to &quot;配置与发现笔记：把基础设施做成可替换入口&quot;">​</a></h1><p>这篇记录的不是某个配置中心的使用教程，而是我对“配置与发现”的理解变化。</p><p>一开始配置只是 <code>.env</code>。模型地址、数据库、缓存、对象存储、沙箱开关，都可以写进去。后来服务多了、能力多了、环境多了，配置中心就不只是保存 key-value，它还可能成为能力发现入口。</p><h2 id="为什么-env-后面会不够" tabindex="-1">为什么 <code>.env</code> 后面会不够 <a class="header-anchor" href="#为什么-env-后面会不够" aria-label="Permalink to &quot;为什么 `.env` 后面会不够&quot;">​</a></h2><p>单服务、单环境时，本地配置很舒服。问题出现在多进程、多环境、多能力之后。</p><p>业务服务和执行服务需要服务注册。工具能力可能来自外部注册中心。Skill 可能需要平台分发。远端 Agent 也需要被发现和治理。</p><p>如果这些都写死在配置文件里，每次扩环境、灰度、切 provider 都会很痛。</p><h2 id="provider-化的思路" tabindex="-1">Provider 化的思路 <a class="header-anchor" href="#provider-化的思路" aria-label="Permalink to &quot;Provider 化的思路&quot;">​</a></h2>',8)),l(r,{code:"flowchart%20TD%0A%20%20%20%20App%5B%22%E5%BA%94%E7%94%A8%E5%90%AF%E5%8A%A8%22%5D%20--%3E%20ConfigProvider%5B%22%E9%85%8D%E7%BD%AE%20Provider%22%5D%0A%20%20%20%20ConfigProvider%20--%3E%20Env%5B%22%E7%8E%AF%E5%A2%83%E5%8F%98%E9%87%8F%20%2F%20%E6%9C%AC%E5%9C%B0%E9%85%8D%E7%BD%AE%22%5D%0A%20%20%20%20ConfigProvider%20--%3E%20ConfigCenter%5B%22%E9%85%8D%E7%BD%AE%E4%B8%AD%E5%BF%83%22%5D%0A%0A%20%20%20%20App%20--%3E%20ServiceRegistry%5B%22%E6%9C%8D%E5%8A%A1%E6%B3%A8%E5%86%8C%22%5D%0A%20%20%20%20ServiceRegistry%20--%3E%20Business%5B%22%E4%B8%9A%E5%8A%A1%E6%9C%8D%E5%8A%A1%E5%AE%9E%E4%BE%8B%22%5D%0A%20%20%20%20ServiceRegistry%20--%3E%20Runtime%5B%22%E6%89%A7%E8%A1%8C%E6%9C%8D%E5%8A%A1%E5%AE%9E%E4%BE%8B%22%5D%0A%0A%20%20%20%20App%20--%3E%20CapabilityProvider%5B%22%E8%83%BD%E5%8A%9B%20Provider%22%5D%0A%20%20%20%20CapabilityProvider%20--%3E%20Tools%5B%22%E5%B7%A5%E5%85%B7%E5%8F%91%E7%8E%B0%22%5D%0A%20%20%20%20CapabilityProvider%20--%3E%20Skills%5B%22Skill%20%E5%90%8C%E6%AD%A5%22%5D%0A%20%20%20%20CapabilityProvider%20--%3E%20Agents%5B%22%E8%BF%9C%E7%AB%AF%20Agent%20%E5%8F%91%E7%8E%B0%22%5D%0A"}),e[1]||(e[1]=a('<p>重点不是必须使用某个基础设施，而是要有 provider 抽象。没有配置中心时，系统应该还能用本地配置跑起来；有配置中心时，平台能力可以从那里接入。</p><p>工具、Skill、远端 Agent 从哪里发现，不应该影响主执行逻辑。主流程只依赖统一 provider 结果。</p><h2 id="配置中心不是自动热更新" tabindex="-1">配置中心不是自动热更新 <a class="header-anchor" href="#配置中心不是自动热更新" aria-label="Permalink to &quot;配置中心不是自动热更新&quot;">​</a></h2><p>这是一个容易误解的点。配置能从中心读取，不代表所有配置都能运行时热更新。</p><p>有些配置只在启动时读取，有些配置更新后需要重建上下文，有些配置会影响 provider 初始化，有些配置可以动态生效。这些边界必须写清楚。</p><h2 id="踩过的坑" tabindex="-1">踩过的坑 <a class="header-anchor" href="#踩过的坑" aria-label="Permalink to &quot;踩过的坑&quot;">​</a></h2><p>第一个坑，是把配置中心当 <code>.env</code> 替代品。只迁移 key-value，价值有限。</p><p>第二个坑，是基础设施逻辑渗透业务。代码里到处判断当前 provider，后面很难换。</p><p>第三个坑，是热更新边界不清。大家以为改了配置就生效，实际可能要重启。</p><p>第四个坑，是能力发现等于能力可信。一个工具被发现，只说明它存在，不说明它能绕过审批。</p><p>第五个坑，是缺少配置来源可观测。线上排查时，必须知道当前值来自哪里。</p><h2 id="现在的记录" tabindex="-1">现在的记录 <a class="header-anchor" href="#现在的记录" aria-label="Permalink to &quot;现在的记录&quot;">​</a></h2><p>如果再做一次，我会从第一天定义配置优先级：环境变量、本地文件、配置中心、默认值之间谁覆盖谁。</p><p>能力 provider 要有版本、签名、审计和健康状态。尤其是工具和 Skill，它们会直接影响 Agent 行为，不能当普通配置项。</p><p>一句话总结：配置中心的价值不只是集中配置，而是让配置、服务和能力发现都能通过可替换 provider 接入。</p><h2 id="podcast-提纲" tabindex="-1">Podcast 提纲 <a class="header-anchor" href="#podcast-提纲" aria-label="Permalink to &quot;Podcast 提纲&quot;">​</a></h2><ol><li>为什么 <code>.env</code> 后面会不够用。</li><li>配置中心和能力发现有什么关系。</li><li>为什么基础设施能力要做成 provider。</li><li>热更新边界为什么要写清楚。</li><li>能力发现为什么不等于能力可信。</li><li>配置来源可观测性的重要性。</li><li>如果重做，我会先设计哪些 provider 边界。</li></ol>',17))])}const _=i(E,[["render",n]]);export{B as __pageData,_ as default};
